function makeUniversalMixedQuiz(quizzes) {
  const target = 100;
  const pool = [];
  quizzes.forEach((quiz, quizIndex) => {
    (quiz.items || []).forEach((item, itemIndex) => {
      pool.push({
        ...item,
        _sourceQuizTitle: quiz.title,
        _sourceSubject: quiz.subject,
        _sourceModule: quiz.module,
        _sourceOrder: `${quizIndex}-${itemIndex}`,
      });
    });
  });

  const sectionPriority = ["MCQ", "True/False", "Matching", "Identification", "Nomenclature", "Structure", "Sequencing", "Case", "Application", "Skill"];
  const selected = [];
  let total = 0;

  for (const priority of sectionPriority) {
    const matches = pool
      .filter((item) => normalizeText(item.section || item.type || "").includes(normalizeText(priority)))
      .sort((a, b) => hashString(`${a._sourceSubject}-${a._sourceModule}-${a.id}`) - hashString(`${b._sourceSubject}-${b._sourceModule}-${b.id}`));
    for (const item of matches) {
      if (total >= target) break;
      if (selected.some((chosen) => chosen._sourceOrder === item._sourceOrder)) continue;
      const originalPoints = Number(item.points) || 1;
      const points = Math.min(originalPoints, target - total);
      if (points <= 0) continue;
      selected.push({
        ...item,
        id: `mix-${selected.length + 1}-${item.id}`,
        number: selected.length + 1,
        points,
        section: `${String(item._sourceSubject || "Subject").replace(/\/.*$/, "")} • ${item.section || item.type}`,
        source: `${item.source || "Verified quiz bank"} Source quiz: ${item._sourceQuizTitle}.`,
      });
      total += points;
    }
    if (total >= target) break;
  }

  return {
    id: "universal-mixed-master-100",
    title: "Mixed Practice Quiz",
    subject: "Mixed Review",
    module: "All available quiz sets",
    description: "A 100-point mixed practice set made from the available quizzes. Use it when you want a broader review session.",
    version: APP_VERSION,
    badge: "MIXED",
    totalPoints: total || target,
    goal: Math.ceil((total || target) * 0.6),
    items: selected,
    isGeneratedMixedQuiz: true,
  };
}

const QUIZ_BANK = [makeUniversalMixedQuiz(QUIZZES), ...QUIZZES];

