function cls(...xs) { return xs.filter(Boolean).join(" "); }
function normalizeText(value) {
  return String(value ?? "")
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[₀⁰]/g, "0").replace(/[₁¹]/g, "1").replace(/[₂²]/g, "2").replace(/[₃³]/g, "3")
    .replace(/[₄⁴]/g, "4").replace(/[₅⁵]/g, "5").replace(/[₆⁶]/g, "6").replace(/[₇⁷]/g, "7")
    .replace(/[₈⁸]/g, "8").replace(/[₉⁹]/g, "9")
    .replace(/π/g, "pi")
    .replace(/[^a-z0-9+]+/g, " ")
    .trim();
}
function choiceLetterToIndex(value) {
  const s = String(value ?? "").trim().toUpperCase();
  return /^[A-J]$/.test(s) ? s.charCodeAt(0) - 65 : -1;
}
function scoreCase(answer, keywords) {
  const text = normalizeText(answer);
  if (!text) return { score: 0, matched: [] };
  const matched = (keywords || []).filter(k => text.includes(normalizeText(k)));
  return { score: matched.length, matched };
}
function getCorrectAnswer(q) {
  if (!q) return "";
  if (q.type === "case") return q.sampleAnswer || "";
  if (Array.isArray(q.choices)) {
    if (typeof q.answer === "number") return q.choices[q.answer] ?? "";
    const letterIndex = choiceLetterToIndex(q.answer);
    if (letterIndex >= 0 && letterIndex < q.choices.length) return q.choices[letterIndex] ?? "";
  }
  return q.answer ?? "";
}
function isCorrectChoice(q, ans) {
  if (!q || q.type === "case" || ans === undefined || ans === null || ans === "") return false;
  const correct = getCorrectAnswer(q);
  return normalizeText(ans) === normalizeText(correct);
}
function getAnswerLabel(q, ans) {
  if (ans === undefined || ans === null || ans === "") return "No answer";
  if (!Array.isArray(q?.choices)) return String(ans);
  const idx = q.choices.findIndex(c => normalizeText(c) === normalizeText(ans));
  return idx >= 0 ? `${String.fromCharCode(65 + idx)}. ${ans}` : String(ans);
}
function getCorrectLabel(q) {
  const correct = getCorrectAnswer(q);
  if (!Array.isArray(q?.choices)) return String(correct || "");
  const idx = q.choices.findIndex(c => normalizeText(c) === normalizeText(correct));
  return idx >= 0 ? `${String.fromCharCode(65 + idx)}. ${correct}` : String(correct || "");
}
function getQuestionScore(q, ans, revealed = true, submitted = false) {
  if (!q) return 0;
  if (q.type === "case") {
    if (!(revealed || submitted) || !String(ans || "").trim()) return 0;
    const total = Math.max(1, q.keywords?.length || 1);
    const sc = scoreCase(ans, q.keywords);
    return Math.min(q.points, Math.round((sc.matched.length / total) * q.points));
  }
  return isCorrectChoice(q, ans) ? q.points : 0;
}
function isQuestionAnswered(q, answers) { const v = answers[q.id]; return q.type === "case" ? Boolean(String(v || "").trim()) : v !== undefined && v !== null && v !== ""; }
function isCaseAcceptable(q, ans) {
  if (!ans) return false;
  const total = Math.max(1, q.keywords?.length || 1);
  const sc = scoreCase(ans, q.keywords);
  return sc.matched.length >= Math.ceil(total * 0.6);
}
function isItemCorrect(q, ans) {
  return q.type === "case" ? isCaseAcceptable(q, ans) : isCorrectChoice(q, ans);
}
function hashString(value) {
  let h = 2166136261;
  for (let i = 0; i < String(value).length; i++) { h ^= String(value).charCodeAt(i); h = Math.imul(h, 16777619); }
  return h >>> 0;
}
function seededRandom(seed) {
  let t = seed >>> 0;
  return function() {
    t += 0x6D2B79F5;
    let r = Math.imul(t ^ (t >>> 15), 1 | t);
    r ^= r + Math.imul(r ^ (r >>> 7), 61 | r);
    return ((r ^ (r >>> 14)) >>> 0) / 4294967296;
  };
}
function shuffleChoices(choices = [], seedText = "") {
  const arr = [...choices];
  const rand = seededRandom(hashString(seedText));
  for (let i = arr.length - 1; i > 0; i--) { const j = Math.floor(rand() * (i + 1)); [arr[i], arr[j]] = [arr[j], arr[i]]; }
  return arr;
}
function stableUniqueChoices(choices = []) {
  const seen = new Set();
  return choices.filter((choice) => {
    const key = normalizeText(choice);
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}
function isTrueFalseItem(item) {
  const section = normalizeText(item?.section || "");
  const choices = (item?.choices || []).map(normalizeText);
  return section.includes("true") || (choices.length === 2 && choices.includes("true") && choices.includes("false"));
}
function isMatchingItem(item) {
  const section = normalizeText(item?.section || "");
  const stem = normalizeText(item?.stem || "");
  return section.includes("matching") || stem.startsWith("identify/match") || stem.startsWith("match:");
}
function isSequencingItem(item) {
  const section = normalizeText(item?.section || "");
  const tags = (item?.tags || []).map(normalizeText).join(" ");
  return item?.type === "sequence" || section.includes("sequencing") || tags.includes("sequencing");
}
function cleanTrueFalseChoices(choices = []) {
  const hasTrue = choices.some((c) => normalizeText(c) === "true");
  const hasFalse = choices.some((c) => normalizeText(c) === "false");
  if (hasTrue && hasFalse) return ["True", "False"];
  return choices;
}
function isNamingOrIdentificationItem(item) {
  const section = normalizeText(item?.section || "");
  const stem = normalizeText(item?.stem || "");
  const tags = (item?.tags || []).map(normalizeText).join(" ");
  const text = `${section} ${stem} ${tags}`;
  return /nomenclature|naming|identify|identification|functional group|structure identification|name this|name the/.test(text) && item?.type !== "case";
}
const NAMING_DISTRACTOR_BANK = [
  "benzene", "toluene / methylbenzene", "phenol / benzenol", "benzoic acid / benzenecarboxylic acid",
  "benzaldehyde / benzenecarbaldehyde", "acetophenone / 1-phenylethanone", "aniline / benzenamine", "styrene / ethenylbenzene",
  "ethanal / acetaldehyde", "acetone / propanone", "formaldehyde / methanal", "vanillin", "acetic acid / ethanoic acid",
  "ethyl ethanoate / ethyl acetate", "ethanamide / acetamide", "ethanenitrile / acetonitrile", "ethanoyl chloride / acetyl chloride",
  "ethanoic anhydride / acetic anhydride", "nitrile", "amide", "ester", "acid chloride / acid halide", "acid anhydride",
  "aldehyde", "ketone", "carboxylic acid", "phenol", "ether", "alcohol"
];
function buildNamingChoiceSet(item, correct, originalChoices = []) {
  const base = stableUniqueChoices([correct, ...originalChoices].filter(Boolean));
  if (base.length >= 4) return base;
  const seedText = `${item?.id || "item"}-${correct}`;
  const distractors = shuffleChoices(NAMING_DISTRACTOR_BANK, seedText)
    .filter((choice) => normalizeText(choice) !== normalizeText(correct) && !base.some((b) => normalizeText(b) === normalizeText(choice)));
  return stableUniqueChoices([...base, ...distractors]).slice(0, 4);
}
function prepareItemForAttempt(item, quizId, attemptKey) {
  if (item.type === "case") return item;
  const originalChoices = stableUniqueChoices(item.choices || []);
  const correct = getCorrectAnswer({ ...item, choices: originalChoices });
  const choiceSeed = isNamingOrIdentificationItem(item)
    ? buildNamingChoiceSet(item, correct, originalChoices)
    : originalChoices;
  const safeChoices = choiceSeed.some((choice) => normalizeText(choice) === normalizeText(correct))
    ? choiceSeed
    : [correct, ...choiceSeed].filter(Boolean);

  if (isTrueFalseItem(item)) {
    return {
      ...item,
      choices: cleanTrueFalseChoices(safeChoices),
      answer: normalizeText(correct) === "true" ? "True" : normalizeText(correct) === "false" ? "False" : correct,
    };
  }

  return {
    ...item,
    type: isNamingOrIdentificationItem(item) ? "select" : item.type,
    choices: shuffleChoices(safeChoices, `${quizId}-${attemptKey}-${item.id}`),
    answer: correct,
  };
}
function getMatchingPromptText(question) {
  const stem = question?.stem || "";
  const match = stem.match(/^(Identify\/Match|Match):\s*(.*)$/i);
  return match?.[2] || stem;
}
function stripMatchingChoicePrefix(choice) {
  return String(choice || "").replace(/^\s*(?:[A-Ja-j]|[0-9]{1,2})\s*[.)\-:]\s+/, "").trim();
}
function displayChoiceText(question, choice) {
  return (isMatchingItem(question) || isSequencingItem(question)) ? stripMatchingChoicePrefix(choice) : choice;
}
function MatchingContext({ question }) {
  if (isSequencingItem(question)) {
    return <div className="matching-context"><b>Sequencing context:</b> Choose the safest order. Read each option from left to right and look for the sequence that protects patient identity, specimen quality, and sharps safety.
      <div className="match-prompt">Procedure to arrange: {question?.stem}</div>
    </div>;
  }
  if (!isMatchingItem(question)) return null;
  return <div className="matching-context"><b>Matching context:</b> Match the prompt below with the most accurate term, reagent, definition, or laboratory action from the choices. Treat each item as one row from a matching table. Candidate letters are intentionally hidden so you answer by meaning, not by letter.
    <div className="match-prompt">Prompt to match: {getMatchingPromptText(question)}</div>
  </div>;
}
function sourceVisible(revealed, submitted, id) { return submitted || Boolean(revealed[id]); }


const PROGRESS_KEY = "mls-quiz-progress-v1";

function readProgressRecords() {
  try {
    const raw = localStorage.getItem(PROGRESS_KEY);
    const data = JSON.parse(raw || "[]");
    return Array.isArray(data) ? data : [];
  } catch {
    return [];
  }
}
function writeProgressRecords(records) {
  try { localStorage.setItem(PROGRESS_KEY, JSON.stringify(records)); } catch {}
}
function saveProgressRecord(record) {
  const records = readProgressRecords();
  records.unshift(record);
  writeProgressRecords(records.slice(0, 250));
}
function clearProgressRecords() { writeProgressRecords([]); }
function secondsToClock(seconds = 0) {
  const s = Math.max(0, Math.round(seconds));
  const m = Math.floor(s / 60);
  const r = s % 60;
  return `${m}:${String(r).padStart(2, "0")}`;
}
function formatDateTime(value) {
  try { return new Date(value).toLocaleString([], { dateStyle: "medium", timeStyle: "short" }); }
  catch { return String(value || ""); }
}
function buildSectionStats(items, answers, submitted = true) {
  const map = {};
  items.forEach((item) => {
    const key = item.section || "General";
    if (!map[key]) map[key] = { section: key, earned: 0, possible: 0, answered: 0, items: 0, correct: 0 };
    const earned = getQuestionScore(item, answers[item.id], true, submitted);
    map[key].earned += earned;
    map[key].possible += item.points || 0;
    map[key].answered += isQuestionAnswered(item, answers) ? 1 : 0;
    map[key].items += 1;
    map[key].correct += isItemCorrect(item, answers[item.id]) ? 1 : 0;
  });
  return Object.values(map).map((section) => ({ ...section, percent: section.possible ? Math.round((section.earned / section.possible) * 1000) / 10 : 0 }));
}
function getWeakestSections(sectionStats = []) {
  return sectionStats
    .filter((section) => section.possible > 0)
    .sort((a, b) => a.percent - b.percent || b.possible - a.possible)
    .slice(0, 3)
    .map((section) => section.section);
}
function makeAttemptRecord(quiz, items, answers, startedAt) {
  const score = items.reduce((sum, item) => sum + getQuestionScore(item, answers[item.id], true, true), 0);
  const sectionStats = buildSectionStats(items, answers, true);
  const now = Date.now();
  const total = quiz.totalPoints || items.reduce((sum, item) => sum + (item.points || 0), 0);
  const percent = total ? Math.round((score / total) * 1000) / 10 : 0;
  return {
    id: `${quiz.id}-${now}`,
    quizId: quiz.id,
    quizTitle: quiz.title,
    subject: quiz.subject,
    module: quiz.module,
    date: new Date(now).toISOString(),
    score,
    totalPoints: total,
    percent,
    goal: quiz.goal,
    passed: score >= quiz.goal,
    answeredCount: items.filter((item) => isQuestionAnswered(item, answers)).length,
    totalItems: items.length,
    timeSpentSeconds: Math.round((now - startedAt) / 1000),
    sectionStats,
    weakestSections: getWeakestSections(sectionStats),
  };
}
function exportProgressCSV(records) {
  const header = ["Date", "Subject", "Module", "Quiz", "Score", "Total", "Percent", "Result", "Time spent", "Weakest sections"];
  const rows = records.map((r) => [
    formatDateTime(r.date), r.subject, r.module, r.quizTitle, r.score, r.totalPoints,
    `${r.percent}%`, r.passed ? "Passed" : "Needs review", secondsToClock(r.timeSpentSeconds),
    (r.weakestSections || []).join(" | "),
  ]);
  const csv = [header, ...rows].map((row) => row.map((cell) => `"${String(cell ?? "").replace(/"/g, '""')}"`).join(",")).join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = "quiz-progress-tracker.csv";
  a.click();
  URL.revokeObjectURL(url);
}
function groupByQuiz(records) {
  const grouped = {};
  records.forEach((r) => {
    if (!grouped[r.quizId]) grouped[r.quizId] = [];
    grouped[r.quizId].push(r);
  });
  return grouped;
}

