function ProgressTracker({ onBack, onOpenSettings, dark, setDark }) {
  const [records, setRecords] = useState(() => readProgressRecords());
  const [filter, setFilter] = useState("All");
  const subjects = ["All", ...Array.from(new Set(records.map((r) => r.subject).filter(Boolean)))];
  const filtered = records.filter((r) => filter === "All" || r.subject === filter);
  const grouped = groupByQuiz(filtered);
  const totalAttempts = filtered.length;
  const latest = filtered[0];
  const best = filtered.reduce((bestRecord, current) => !bestRecord || current.percent > bestRecord.percent ? current : bestRecord, null);
  const average = filtered.length ? Math.round((filtered.reduce((sum, r) => sum + r.percent, 0) / filtered.length) * 10) / 10 : 0;
  const improvedCount = Object.values(grouped).filter((list) => {
    const chronological = [...list].sort((a, b) => new Date(a.date) - new Date(b.date));
    return chronological.length >= 2 && chronological.at(-1).percent > chronological[0].percent;
  }).length;
  function resetProgress() {
    if (confirm("Clear all saved quiz attempts on this browser?")) {
      clearProgressRecords();
      setRecords([]);
    }
  }
  return <main id="main-content" className="wrap"><header className="header"><div><button className="btn" onClick={onBack}>← Back to Quiz Library</button><p className="subject">Quiz Reviewer Beta 5.1</p><h2>Progress tracker</h2><p className="muted">Saved locally on this browser/device. Use it to check whether each quiz attempt is improving over time.</p></div><div className="pillbar"><button className="btn" onClick={() => exportProgressCSV(filtered)} disabled={!filtered.length}>Export CSV</button><button className="btn" onClick={resetProgress} disabled={!records.length}>Reset progress</button><button className="btn" onClick={onOpenSettings}>Settings</button><button className="btn" onClick={()=>setDark(!dark)}>{dark?'Light':'Dark'} mode</button></div></header><div className="toolbar"><div className="pillbar">{subjects.map((s)=><button key={s} className={cls('pill', filter===s && 'active')} onClick={()=>setFilter(s)}>{s}</button>)}</div></div>{!filtered.length ? <div className="empty-state"><h2>No attempts yet</h2><p>Take any quiz and submit it. The app will save your score, time spent, weakest sections, and trend automatically.</p></div> : <><section className="tracker-grid"><div className="metric"><span className="muted">Total attempts</span><br/><b>{totalAttempts}</b></div><div className="metric"><span className="muted">Latest score</span><br/><b>{latest?.score}/{latest?.totalPoints}</b><p className="muted">{latest?.percent}% • {latest?.passed ? 'Passed' : 'Needs review'}</p></div><div className="metric"><span className="muted">Best score</span><br/><b>{best?.percent}%</b><p className="muted">{best?.quizTitle}</p></div><div className="metric"><span className="muted">Average score</span><br/><b>{average}%</b><p className="muted">{improvedCount} quiz set{improvedCount===1?'':'s'} improving</p></div></section><section className="tracker-list">{Object.entries(grouped).map(([quizId, list]) => { const chronological = [...list].sort((a,b)=>new Date(a.date)-new Date(b.date)); const first = chronological[0]; const last = chronological.at(-1); const bestAttempt = chronological.reduce((b,r)=>r.percent>b.percent?r:b, chronological[0]); const diff = Math.round((last.percent - first.percent)*10)/10; const avg = Math.round((chronological.reduce((sum,r)=>sum+r.percent,0)/chronological.length)*10)/10; const latestSections = last.sectionStats || []; return <article key={quizId} className="card tracker-card"><div className="card-top"><div><div className="subject">{last.subject}</div><h2 className="quiz-title">{last.quizTitle}</h2><p className="muted">{last.module}</p></div><span className="points">{chronological.length} attempt{chronological.length===1?'':'s'}</span></div><div className="meta-row"><span className="mini">First {first.percent}%</span><span className="mini">Latest {last.percent}%</span><span className="mini">Best {bestAttempt.percent}%</span><span className="mini">Average {avg}%</span><span className={cls('mini', diff>=0?'trend-up':'trend-down')}>{diff>=0?'+':''}{diff}% trend</span></div><div className="spark">{chronological.slice(-12).map((r,i)=><span key={`${r.id}-${i}`} title={`${r.percent}%`} style={{height:`${Math.max(6, Math.min(54, r.percent * .54))}px`}} />)}</div>{latestSections.length > 0 && <div className="section-bars">{latestSections.map((s)=><div key={s.section} className="section-bar"><span>{s.section}</span><div className="section-track"><div className="section-fill" style={{width:`${Math.max(0, Math.min(100, s.percent))}%`}} /></div><b>{s.percent}%</b></div>)}</div>}<p className="muted"><b>Needs review:</b> {(last.weakestSections || []).join(', ') || 'No weak section recorded'}</p></article> })}</section><div className="card tracker-card" style={{marginTop:16, overflowX:'auto'}}><h2>Recent attempts</h2><table className="attempt-table"><thead><tr><th>Date</th><th>Quiz</th><th>Score</th><th>Result</th><th>Time</th><th>Weakest section</th></tr></thead><tbody>{filtered.slice(0,50).map((r)=><tr key={r.id}><td>{formatDateTime(r.date)}</td><td>{r.quizTitle}</td><td><b>{r.score}/{r.totalPoints}</b> ({r.percent}%)</td><td>{r.passed ? 'Passed' : 'Needs review'}</td><td>{secondsToClock(r.timeSpentSeconds)}</td><td>{(r.weakestSections || []).join(', ')}</td></tr>)}</tbody></table></div></>}</main>;
}



