const AI_PROVIDER_OPTIONS = [
  { id: "puter-deepseek", label: "Deepseek" },
  { id: "puter-gemini", label: "Gemini" },
];
const PUTER_SCRIPT_SRC = "https://js.puter.com/v2/";
function loadPuter() {
  if (typeof window === "undefined") return Promise.reject(new Error("Puter.js is browser-only."));
  if (window.puter?.ai?.chat) return Promise.resolve(window.puter);
  return new Promise((resolve, reject) => {
    const existing = document.querySelector(`script[src="${PUTER_SCRIPT_SRC}"]`);
    const done = () => window.puter?.ai?.chat ? resolve(window.puter) : reject(new Error("Puter.js loaded but puter.ai.chat is unavailable."));
    if (existing) { existing.addEventListener("load", done, { once: true }); existing.addEventListener("error", () => reject(new Error("Failed to load Puter.js.")), { once: true }); return; }
    const script = document.createElement("script");
    script.src = PUTER_SCRIPT_SRC;
    script.async = true;
    script.onload = done;
    script.onerror = () => reject(new Error("Failed to load Puter.js."));
    document.head.appendChild(script);
  });
}
function buildAIStudyPrompt(context) {
  const isHint = context.mode === "hint";
  return `You are an accurate, friendly Medical Laboratory Science quiz tutor.\n\nMode: ${context.mode}\nApp: ${context.appVersion}\nQuiz: ${context.quiz}\nModule: ${context.module}\nSection: ${context.section}\nQuestion: ${context.question}\nChoices: ${JSON.stringify(context.choices || [])}\nStudent answer: ${context.studentAnswer || ""}\nCorrect answer: ${isHint ? "[hidden for hint mode]" : (context.correctAnswer || "")}\nBuilt-in explanation: ${isHint ? "[hidden for hint mode]" : (context.explanation || "")}\n\nRules:\n- Keep the response concise, warm, and useful.\n- If mode is hint, do NOT reveal the exact answer, answer letter, or answer text.\n- If mode is check, compare the student answer with the provided key/rubric and explain what is correct or missing.\n- If mode is lesson, teach the concept in 4-7 short lines with one exam cue.\n- Use only the quiz context provided. Do not invent citations or sources.\n- End with one practical study tip.`;
}
function extractAIText(response) {
  if (typeof response === "string") return response;
  if (response?.message?.content) return response.message.content;
  if (response?.text) return response.text;
  if (Array.isArray(response?.choices)) return response.choices.map((c) => c?.message?.content || c?.text || "").join("\n").trim();
  if (Array.isArray(response?.message?.content)) return response.message.content.map((p) => p?.text || p?.content || "").join("\n").trim();
  return JSON.stringify(response, null, 2);
}
function offlineAIResponse(mode) {
  if (mode === "hint") return "Offline hint: identify the functional group, lab test, or safety principle first. Then eliminate choices that contradict the module rule. Avoid guessing by answer letter.";
  if (mode === "lesson") return "Offline mini lesson: review the built-in explanation after revealing the answer. Focus on the rule, the observation, and the MLS reason behind it.";
  return "Offline check: compare your answer with the built-in key after reveal. Look for missing keywords, wrong functional group, or unsupported lab interpretation.";
}
async function askNetlifyAI(context, provider) {
  const res = await fetch('/.netlify/functions/ai-tutor', {
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body: JSON.stringify({...context, provider})
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error || `AI function failed with ${res.status}`);
  const answer = data.answer || data.error || '';
  if (!answer || data.provider === 'offline' || data.model === 'offline') throw new Error(answer || 'Server AI unavailable.');
  return { text: answer, label: `${data.provider || provider}: ${data.model || 'model'}` };
}
async function askPuterProvider(context, provider) {
  const puter = await loadPuter();
  const model = provider === 'puter-gemini' ? 'google/gemini-2.5-flash' : 'deepseek/deepseek-v4-flash';
  const response = await puter.ai.chat(buildAIStudyPrompt(context), { model });
  const text = extractAIText(response).trim();
  if (!text) throw new Error('Puter returned an empty response.');
  return { text, label: provider === 'puter-gemini' ? 'Gemini' : 'Deepseek' };
}

function AIStudyCoach({ quiz, question, answer, revealed, submitted }) {
  const [open,setOpen]=useState(true);
  const [mode,setMode]=useState('hint');
  const [out,setOut]=useState('');
  const [loading,setLoading]=useState(false);
  const [showContext,setShowContext]=useState(false);
  const [provider,setProvider]=useState(() => {
    const stored = localStorage.getItem('mls-ai-provider');
    return AI_PROVIDER_OPTIONS.some((option) => option.id === stored) ? stored : 'puter-deepseek';
  });
  const [model,setModel]=useState('Deepseek');
  const canReveal = revealed || submitted;
  useEffect(()=>{ localStorage.setItem('mls-ai-provider', provider); }, [provider]);
  const context = {
    mode,
    appVersion: APP_VERSION,
    quiz: quiz.title,
    module: quiz.module,
    section: question.section,
    question: question.stem,
    choices: question.choices,
    studentAnswer: answer || '',
    correctAnswer: canReveal ? getCorrectAnswer(question) : '[hidden until reveal]',
    explanation: canReveal ? question.explanation : '[hidden until reveal]',
    source: canReveal ? question.source : '[hidden while answering]'
  };
  async function ask(nextMode) {
    const nextContext = { ...context, mode: nextMode };
    setMode(nextMode); setLoading(true); setOut('');
    try {
      const selectedProvider = AI_PROVIDER_OPTIONS.some((option) => option.id === provider) ? provider : 'puter-deepseek';
      const result = await askPuterProvider(nextContext, selectedProvider);
      setModel(result.label);
      setOut(result.text);
    } catch(e) {
      setModel('Offline Tutor');
      setOut(`${offlineAIResponse(nextMode)}\n\nCoach note: ${e.message || 'provider unavailable'}`);
    } finally { setLoading(false); }
  }
  return <aside className="card ai-panel"><div style={{display:'flex',justifyContent:'space-between',gap:8,alignItems:'center'}}><div><b>Study Coach</b><div className="muted" style={{fontSize:'.82rem'}}>{model} • answer key hidden until reveal</div></div><button className="pill" onClick={()=>setOpen(!open)}>{open?'Hide':'Open'}</button></div>{open&&<><label className="muted" style={{fontSize:'.82rem',fontWeight:800}}>Study support</label><select className="search" style={{width:'100%',padding:'10px 12px'}} value={provider} onChange={(e)=>{setProvider(e.target.value);setOut('');setModel(AI_PROVIDER_OPTIONS.find(p=>p.id===e.target.value)?.label || 'coach provider');}}>{AI_PROVIDER_OPTIONS.map(p=><option key={p.id} value={p.id}>{p.label}</option>)}</select><div className="ai-buttons"><button className="btn" onClick={()=>ask('hint')} disabled={loading}>Smart Hint</button><button className="btn" onClick={()=>ask('check')} disabled={loading}>Check Answer</button><button className="btn" onClick={()=>ask('lesson')} disabled={loading}>Mini Lesson</button><button className="btn" onClick={()=>setShowContext(!showContext)}>Context</button></div><div className="ai-output">{loading?'Thinking...': out || 'Choose Deepseek or Gemini, then ask for a guided hint, answer check, or mini lesson. Hint mode does not use the answer key.'}</div>{showContext&&<pre className="context-box">{JSON.stringify({...context, provider: AI_PROVIDER_OPTIONS.find(p=>p.id===provider)?.label || provider},null,2)}</pre>}</>}</aside>
}

function QuizRunner({ quiz, onBack, dark, setDark, settings, onOpenSettings }) {
  const [idx,setIdx]=useState(0), [answers,setAnswers]=useState({}), [revealed,setRevealed]=useState({}), [submitted,setSubmitted]=useState(false), [navOpen,setNavOpen]=useState(false), [toast,setToast]=useState('');
  const [attemptKey, setAttemptKey] = useState(() => Date.now());
  const [attemptStart, setAttemptStart] = useState(() => Date.now());
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [attemptSaved, setAttemptSaved] = useState(false);
  const [reviewFilter, setReviewFilter] = useState('mistakes');
  const attemptSavedRef = useRef(false);
  const timers=useRef([]);
  function clearTimers() { timers.current.forEach(clearTimeout); timers.current = []; }
  useEffect(()=>()=>clearTimers(),[]);
  useEffect(() => {
    if (submitted) return;
    const updateElapsed = () => setElapsedSeconds(Math.max(0, Math.round((Date.now() - attemptStart) / 1000)));
    updateElapsed();
    const interval = setInterval(updateElapsed, 1000);
    return () => clearInterval(interval);
  }, [attemptStart, submitted]);
  const items = useMemo(() => quiz.items.map((item) => prepareItemForAttempt(item, quiz.id, attemptKey)), [quiz, attemptKey]);
  const q=items[idx] || items[0]; const answeredCount=items.filter(it=>isQuestionAnswered(it,answers)).length; const progress=(answeredCount/items.length)*100;
  function saveAttemptOnce() {
    if (attemptSavedRef.current) return;
    saveProgressRecord(makeAttemptRecord(quiz, items, answers, attemptStart));
    attemptSavedRef.current = true;
    setAttemptSaved(true);
  }
  function finishQuiz() {
    const unanswered = items.length - answeredCount;
    if (!submitted && unanswered > 0 && !confirm(`You still have ${unanswered} unanswered item${unanswered === 1 ? "" : "s"}. Submit anyway?`)) return;
    clearTimers();
    setElapsedSeconds(Math.max(0, Math.round((Date.now() - attemptStart) / 1000)));
    saveAttemptOnce();
    setSubmitted(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }
  function resetAttempt() {
    clearTimers();
    attemptSavedRef.current = false;
    setSubmitted(false); setIdx(0); setAnswers({}); setRevealed({}); setAttemptKey(Date.now()); setAttemptStart(Date.now()); setElapsedSeconds(0); setAttemptSaved(false); setReviewFilter('mistakes'); setToast('');
  }
  function autoNext(fromIndex) {
    if (!settings?.autoNext) return;
    const t=setTimeout(()=>{
      setIdx((current) => current === fromIndex && current < items.length - 1 ? current + 1 : current);
    }, AUTO_NEXT_DELAY_MS);
    timers.current.push(t);
  }
  function reveal(id, message) { setRevealed(r=>({...r,[id]:true})); setToast(message); const t=setTimeout(()=>setToast(''),1200); timers.current.push(t); autoNext(idx); }
  function choose(ans) { if(revealed[q.id]||submitted) return; setAnswers(a=>({...a,[q.id]:ans})); const ok=isCorrectChoice(q,ans); reveal(q.id, ok?'Correct':'Needs review'); }
  function checkCase() { const v=answers[q.id]||''; if(!String(v).trim()){ setToast('Type an answer first'); const t=setTimeout(()=>setToast(''),1200); timers.current.push(t); return; } const sc=scoreCase(v,q.keywords); const ratio = q.keywords?.length ? sc.matched.length/q.keywords.length : 0; reveal(q.id, ratio>.65?'Good response': ratio>.25?'Partial':'Needs review'); }
  function currentScore() { return items.reduce((sum,it)=> sum + getQuestionScore(it, answers[it.id], Boolean(revealed[it.id]), submitted), 0); }
  const score=currentScore();
  const mistakeCount = items.filter((it) => !isItemCorrect(it, answers[it.id])).length;
  const reviewItems = reviewFilter === 'mistakes' ? items.filter((it) => !isItemCorrect(it, answers[it.id])) : items;
  if(submitted) return <main id="main-content" className="wrap"><button className="btn" onClick={onBack}>← Quiz Library</button><section className="score-hero"><div className="card scorebox"><span className="badge">Quiz Reviewer • Beta 5.1 Results</span><h1>{score}/{quiz.totalPoints}</h1><p className="subtitle">Goal: {quiz.goal} points. {score>=quiz.goal?'Passed the 60% goal.':'Below goal — retry and focus on items marked Needs review.'}</p><div className="pillbar"><button className="btn primary" onClick={resetAttempt}>Retry fresh</button><button className="btn" onClick={onBack}>Back to library</button><button className="btn" onClick={()=>setDark(!dark)}>{dark?'Light':'Dark'} mode</button></div></div><div className="card scorebox"><h2>Quiz summary</h2><p><b>{quiz.title}</b></p><p className="muted">{quiz.description}</p><p className="muted"><b>Time spent:</b> {secondsToClock(elapsedSeconds)}</p><p className="muted"><b>Review:</b> {mistakeCount} item{mistakeCount===1?'':'s'} marked for review. Use the buttons below to check only mistakes or the whole quiz.</p><p className="muted">Sources and explanations are now visible because the quiz is submitted. This attempt was saved to the Progress Tracker on this browser.</p></div></section><section className="card review-toolbar"><div><h2>Review your answers</h2><p className="muted">Switch between your mistakes and the full answer key. This helps you focus on weak points first without losing the complete quiz review.</p></div><div className="pillbar"><button className={cls('pill', reviewFilter==='mistakes'&&'active')} onClick={()=>setReviewFilter('mistakes')}>Mistakes only ({mistakeCount})</button><button className={cls('pill', reviewFilter==='all'&&'active')} onClick={()=>setReviewFilter('all')}>Whole quiz ({items.length})</button></div></section>{reviewFilter==='mistakes'&&mistakeCount===0?<div className="empty-state"><h2>No mistakes found</h2><p>You answered every checked item correctly or acceptably. Use Whole quiz to review the full answer key and explanations.</p></div>:<section className="review-grid">{reviewItems.map((it)=>{ const originalIndex=items.findIndex(x=>x.id===it.id); const ans=answers[it.id]; const ok=isItemCorrect(it,ans); return <div key={it.id} className={cls('review-item', ok ? 'review-correct' : 'review-mistake')}><b>Item {originalIndex+1} • {it.section} • {it.points} pt{it.points>1?'s':''}</b>{it.structure&&<div className="structure-card" style={{maxWidth:260,margin:"10px 0"}}><StructureSketch id={it.structure} /></div>}<p>{it.stem}</p>{it.hint&&<p className="muted"><b>Hint used:</b> {it.hint}</p>}<p><b>Your answer:</b> {getAnswerLabel(it, ans)}</p><p><b>Status:</b> {ok?'Correct/acceptable':'Needs review'}</p><p><b>Answer key:</b> {it.type==='case' ? it.sampleAnswer : getCorrectLabel(it)}</p><p><b>Explanation:</b> {it.explanation}</p><p className="muted"><b>Source basis:</b> {it.source}</p></div> })}</section>}</main>;
  return <main id="main-content" className="wrap"><div className="nav-panel"><div className="card nav-mini"><div><b>Question Navigator</b><div className="muted">{idx+1}/{items.length} • {answeredCount} answered • {secondsToClock(elapsedSeconds)}</div></div><button className="btn primary" onClick={()=>setNavOpen(!navOpen)}>{navOpen?'Close':'Open'}</button></div>{navOpen&&<div className="card nav-body"><div className="nav-grid">{items.map((it,i)=>{ const ans=answers[it.id]; const ok=isItemCorrect(it,ans); return <button key={it.id} className={cls('nav-num',i===idx&&'current',isQuestionAnswered(it,answers)&&'done',revealed[it.id]&&!ok&&'revealed wrong')} onClick={()=>{setIdx(i);setNavOpen(false);}}>{i+1}</button> })}</div><button style={{width:'100%',marginTop:10}} className="btn primary" onClick={finishQuiz}>Submit now</button></div>}</div>{toast&&<div className="badge" style={{position:'fixed',left:'50%',top:20,transform:'translateX(-50%)',zIndex:80}}>{toast}</div>}<header className="header"><div><button className="btn" onClick={onBack}>← Back to Quiz Library</button><p className="subject">{quiz.subject} • {quiz.module}</p><h2>{quiz.title}</h2><p className="muted">{quiz.description}</p></div><div className="pillbar"><button className="btn" onClick={onOpenSettings}>Settings</button><button className="btn" onClick={()=>setDark(!dark)}>{dark?'Light':'Dark'} mode</button><button className="btn primary" onClick={finishQuiz}>Submit Quiz</button></div></header><div className="progress"><div className="bar" style={{width:`${progress}%`}} /></div><div className="stat-grid"><div className="stat"><span className="muted">Answered</span><br/><b>{answeredCount}/{items.length}</b></div><div className="stat"><span className="muted">Current score</span><br/><b>{score}/{quiz.totalPoints}</b></div><div className="stat"><span className="muted">Elapsed time</span><br/><b>{secondsToClock(elapsedSeconds)}</b></div><div className="stat"><span className="muted">60% goal</span><br/><b>{quiz.goal} pts</b></div><div className="stat"><span className="muted">Current part</span><br/><b>{q.section}</b></div></div><section className="quiz-layout"><article className="card question-card"><div className="q-head"><span className="section-chip">{q.section}</span><span className="item-chip">Item {idx+1} / {items.length} • {q.points} pt{q.points>1?'s':''}</span></div>{q.structure&&<div className="structure-wrap"><div className="structure-card"><StructureSketch id={q.structure} /></div><div className="structure-meta"><b>Structure reference</b><br/><span className="hidden-note">MolView-style structure:</span> choose the best answer from the choices. Name, SMILES, and formula appear only after reveal.</div></div>}{settings?.showSectionContext && <MatchingContext question={q}/>} {isNamingOrIdentificationItem(q)&&<div className="naming-note"><b>Naming practice:</b> Look at the structure or formula, then choose the best name or functional group.</div>}<h3 className="stem">{q.stem}</h3>{q.type==='case'?<div>{q.hint&&<div className="application-hint"><b>Hint:</b> {q.hint}</div>}<textarea className="casebox" placeholder="Type your concise scientific answer here..." value={answers[q.id]||''} onChange={e=>setAnswers(a=>({...a,[q.id]:e.target.value}))} disabled={revealed[q.id]}/><div className="actions"><button className="btn primary" onClick={checkCase} disabled={revealed[q.id]}>Check this item now</button></div></div>:<div className={cls("choice-grid", isTrueFalseItem(q) && "tf-grid", isMatchingItem(q) && "matching", isSequencingItem(q) && "sequencing-grid")}>{q.choices.map((c,i)=>{ const selected=answers[q.id]===c; const show=revealed[q.id]; const correct=isCorrectChoice(q,c); return <button key={`${q.id}-${c}-${i}`} className={cls("choice", (isMatchingItem(q) || isSequencingItem(q)) && "matching-choice", show&&correct&&"correct", show&&selected&&!correct&&"wrong")} onClick={()=>choose(c)} disabled={show}>{!(isMatchingItem(q)||isSequencingItem(q))&&<span className="letter">{String.fromCharCode(65+i)}</span>}<span className="choice-text"><span>{displayChoiceText(q,c)}</span>{isMatchingItem(q)&&<span className="choice-note">Candidate match for: {getMatchingPromptText(q)}</span>}{isSequencingItem(q)&&<span className="choice-note">Read this option as a complete order.</span>}</span></button> })}</div>}{revealed[q.id]&&<div className={cls('feedback', q.type==='case' || isCorrectChoice(q,answers[q.id]) ? 'good':'bad')}><b>{q.type==='case'?'Sample answer / rubric':'Answer key'}:</b> {q.type==='case' ? q.sampleAnswer : getCorrectLabel(q)}<br/><b>Item score:</b> {getQuestionScore(q, answers[q.id], true, submitted)}/{q.points}<br/><b>Explanation:</b> {q.explanation}<br/><span className="muted"><b>Source basis:</b> {q.source}</span>{q.structure&&<><br/><span className="muted"><b>MolView-compatible:</b> {STRUCTURES[q.structure]?.name} • {STRUCTURES[q.structure]?.smiles} • {STRUCTURES[q.structure]?.formula}</span></>}</div>}<div className="actions"><button className="btn" onClick={()=>setIdx(Math.max(0,idx-1))} disabled={idx===0}>Previous</button><button className="btn" onClick={()=>setIdx(Math.min(items.length-1,idx+1))} disabled={idx===items.length-1}>Next</button></div></article><AIStudyCoach quiz={quiz} question={q} answer={answers[q.id]} revealed={revealed[q.id]} submitted={submitted} /></section></main>;
}

export default function App() {
  const [dark,setDark]=useState(()=>localStorage.getItem('universal-quiz-dark')==='true' || localStorage.getItem('beta31-dark')==='true');
  const [settings,setSettings]=useState(()=>readSettings());
  const [quizId,setQuizId]=useState(null);
  const [page,setPage]=useState('library');
  useEffect(()=>{document.documentElement.dataset.theme=dark?'dark':'light'; localStorage.setItem('universal-quiz-dark',String(dark));},[dark]);
  useEffect(()=>{writeSettings(settings);},[settings]);
  const active=QUIZ_BANK.find(q=>q.id===quizId);
  const appClass = cls('app', settings.largeText && 'large-text', settings.highContrast && 'high-contrast', settings.reducedMotion && 'reduced-motion', settings.compactMode && 'compact-mode');
  return <div className={appClass}><AppStyles/><a className="skip-link" href="#main-content">Skip to main content</a>{page==='settings'?<SettingsPanel dark={dark} setDark={setDark} settings={settings} setSettings={setSettings} onBack={()=>setPage(active ? 'library' : 'library')}/>:page==='tracker'?<ProgressTracker dark={dark} setDark={setDark} onOpenSettings={()=>setPage('settings')} onBack={()=>setPage('library')}/>:active?<QuizRunner quiz={active} dark={dark} setDark={setDark} settings={settings} onOpenSettings={()=>setPage('settings')} onBack={()=>setQuizId(null)}/>:<Library dark={dark} setDark={setDark} onStart={(id)=>{setQuizId(id);setPage('library');}} onOpenTracker={()=>setPage('tracker')} onOpenSettings={()=>setPage('settings')}/>}</div>
}
